import React, { useEffect, useState } from 'react';
import toast from 'react-hot-toast';
import { adminApi } from '../api/client';

export default function AdminDashboard() {
  const [dash,  setDash]  = useState(null);
  const [users, setUsers] = useState([]);
  const [msg,   setMsg]   = useState('');

  useEffect(() => {
    adminApi.getDashboard().then(({ data }) => setDash(data.data));
    adminApi.getUsers().then(({ data }) => setUsers(data.data?.content || []));
  }, []);

  const toggleActive = async (user) => {
    try {
      await adminApi.setUserActive(user.id, !user.active);
      setUsers((u) => u.map((x) => x.id === user.id ? { ...x, active: !x.active } : x));
      toast.success(user.active ? 'Bloklandi' : 'Faollashtirildi');
    } catch { toast.error('Xato'); }
  };

  const broadcast = async () => {
    if (!msg.trim()) return;
    try {
      await adminApi.broadcast(msg, null);
      toast.success('SMS yuborilmoqda...');
      setMsg('');
    } catch { toast.error('Xato'); }
  };

  return (
    <div style={s.page}>
      <h2 style={s.title}>Admin panel</h2>

      {dash && (
        <div style={s.grid}>
          {[
            { label:'Foydalanuvchilar', value: dash.totalUsers },
            { label:'Premium', value: dash.premiumSubs, amber: true },
            { label:'Biznes', value: dash.businessSubs, amber: true },
            { label:'Faol kuryerlar', value: dash.activeCouriers },
            { label:'Aktiv buyurtmalar', value: dash.activeOrders },
            { label:'Kutilayotgan', value: dash.pendingOrders },
          ].map(({ label, value, amber }) => (
            <div key={label} style={s.statCard}>
              <div style={{ fontFamily:'Syne,sans-serif', fontWeight:800, fontSize:24,
                            color: amber ? '#EF9F27' : '#0D7A6A' }}>{value ?? '—'}</div>
              <div style={{ fontSize:12, color:'#6b8080', marginTop:3 }}>{label}</div>
            </div>
          ))}
        </div>
      )}

      {/* Broadcast */}
      <div style={s.card}>
        <div style={s.sectionTitle}>📢 Ommaviy SMS</div>
        <div style={{ display:'flex', gap:10 }}>
          <input style={s.input} placeholder="Barcha foydalanuvchilarga xabar..."
            value={msg} onChange={(e) => setMsg(e.target.value)} />
          <button style={s.btnPrimary} onClick={broadcast}>Yuborish</button>
        </div>
      </div>

      {/* Users table */}
      <div style={s.card}>
        <div style={s.sectionTitle}>👥 Foydalanuvchilar</div>
        <table style={s.table}>
          <thead>
            <tr>{['Ism','Telefon','Rol','Holat','Amal'].map((h) =>
              <th key={h} style={s.th}>{h}</th>)}</tr>
          </thead>
          <tbody>
            {users.map((u) => (
              <tr key={u.id}>
                <td style={s.td}>{u.fullName || '—'}</td>
                <td style={s.td}>{u.phone}</td>
                <td style={s.td}><span style={s.roleBadge}>{u.role}</span></td>
                <td style={s.td}>
                  <span style={{ color: u.active ? '#3B6D11' : '#A32D2D', fontWeight:600, fontSize:12 }}>
                    {u.active ? 'Faol' : 'Bloklangan'}
                  </span>
                </td>
                <td style={s.td}>
                  <button style={s.btnSm} onClick={() => toggleActive(u)}>
                    {u.active ? 'Bloklash' : 'Ochish'}
                  </button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}

const s = {
  page:        { maxWidth:900, margin:'0 auto', padding:16 },
  title:       { fontFamily:'Syne,sans-serif', fontWeight:800, fontSize:22, color:'#1a2e2a', marginBottom:16 },
  grid:        { display:'grid', gridTemplateColumns:'repeat(3,1fr)', gap:12, marginBottom:16 },
  statCard:    { background:'#fff', border:'1px solid rgba(13,122,106,0.15)', borderRadius:12, padding:'14px 16px', textAlign:'center' },
  card:        { background:'#fff', border:'1px solid rgba(13,122,106,0.15)', borderRadius:14, padding:16, marginBottom:14 },
  sectionTitle:{ fontFamily:'Syne,sans-serif', fontWeight:700, fontSize:15, marginBottom:12 },
  input:       { flex:1, padding:'10px 13px', border:'1px solid rgba(13,122,106,0.2)', borderRadius:9, fontSize:14, outline:'none' },
  btnPrimary:  { padding:'10px 20px', background:'#0D7A6A', color:'#fff', border:'none', borderRadius:9, fontSize:14, fontWeight:600, cursor:'pointer' },
  btnSm:       { padding:'5px 12px', background:'transparent', color:'#0D7A6A', border:'1px solid rgba(13,122,106,0.3)', borderRadius:7, fontSize:12, cursor:'pointer' },
  table:       { width:'100%', borderCollapse:'collapse', fontSize:13 },
  th:          { textAlign:'left', padding:'8px 10px', borderBottom:'1px solid rgba(0,0,0,0.08)', color:'#6b8080', fontWeight:600, fontSize:12 },
  td:          { padding:'10px 10px', borderBottom:'1px solid rgba(0,0,0,0.04)' },
  roleBadge:   { background:'#E1F5EE', color:'#085041', fontSize:11, fontWeight:700, padding:'2px 8px', borderRadius:6 },
};
